<?php $page_title='Thương hiệu';require __DIR__.'/_layout_start.php';require_once __DIR__.'/../models/AdminCatalog.php';$m=new AdminCatalog(db_connect());$edit=(int)($_GET['edit']??0);$row=$edit?($m->findBrand($edit)):null;if(is_post()){$id=(int)($_POST['id']??0); if('brands.php'==='categories.php')$m->saveCategory(['ten_thuong_hieu'=>$_POST['name'],'trang_thai'=>$_POST['trang_thai']],$id); else $m->saveBrand(['ten_thuong_hieu'=>$_POST['name'],'trang_thai'=>$_POST['trang_thai']],$id); redirect('admin/brands.php');}$rows=$m->brands();?><h1>Thương hiệu</h1><div class="row"><div class="col-md-4"><form method="post" class="bg-white p-4 rounded-4"><input type="hidden" name="id" value="<?=h($row['id_thuong_hieu']??0)?>"><input name="name" class="form-control mb-2" value="<?=h($row['ten_thuong_hieu']??'')?>" placeholder="Tên"><select name="trang_thai" class="form-select mb-2"><option value="hien">Hiện</option><option value="an">Ẩn</option></select><button class="btn btn-primary">Lưu</button></form></div><div class="col-md-8"><div class="bg-white p-4 rounded-4"><table class="table"><?php foreach($rows as $r):?><tr><td><?=h($r['ten_thuong_hieu'])?></td><td><?=h($r['trang_thai'])?></td><td><a href="<?=BASE_URL?>/admin/brands.php?edit=<?=$r['id_thuong_hieu']?>" class="btn btn-sm btn-outline-primary">Sửa</a></td></tr><?php endforeach;?></table></div></div></div><?php require __DIR__.'/_layout_end.php';?>
